import os
import json
from typing import List, Dict, Any
import numpy as np
from dataclasses import dataclass
import pickle


@dataclass
class Document:
    content: str
    metadata: Dict[str, Any]
    embedding: np.ndarray = None


class SimpleVectorDB:
    def __init__(self):
        self.documents: List[Document] = []
        self.embeddings: np.ndarray = None
    
    def add_documents(self, documents: List[Document]):
        self.documents.extend(documents)
        embeddings = [doc.embedding for doc in documents]
        if self.embeddings is None:
            self.embeddings = np.array(embeddings)
        else:
            self.embeddings = np.vstack([self.embeddings, np.array(embeddings)])
    
    def search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Document]:
        if self.embeddings is None or len(self.documents) == 0:
            return []
        
        similarities = np.dot(self.embeddings, query_embedding) / (
            np.linalg.norm(self.embeddings, axis=1) * np.linalg.norm(query_embedding)
        )
        
        top_indices = np.argsort(similarities)[::-1][:top_k]
        return [self.documents[i] for i in top_indices]
    
    def save(self, filepath: str):
        with open(filepath, 'wb') as f:
            pickle.dump({'documents': self.documents, 'embeddings': self.embeddings}, f)
    
    def load(self, filepath: str):
        with open(filepath, 'rb') as f:
            data = pickle.load(f)
            self.documents = data['documents']
            self.embeddings = data['embeddings']


class SimpleEmbedder:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        np.random.seed(42)
    
    def embed_text(self, text: str) -> np.ndarray:
        words = text.lower().split()
        embedding = np.zeros(self.dimension)
        
        for word in words:
            word_hash = hash(word) % (2**32)
            np.random.seed(word_hash)
            word_embedding = np.random.randn(self.dimension)
            embedding += word_embedding
        
        if len(words) > 0:
            embedding /= len(words)
        
        norm = np.linalg.norm(embedding)
        if norm > 0:
            embedding /= norm
        
        return embedding
    
    def embed_batch(self, texts: List[str]) -> List[np.ndarray]:
        return [self.embed_text(text) for text in texts]


class MockLLM:
    def generate(self, prompt: str, max_tokens: int = 500) -> str:
        context_start = prompt.find("Context Documents:")
        question_start = prompt.find("Question:")
        
        if context_start != -1 and question_start != -1:
            context = prompt[context_start:question_start].strip()
            question = prompt[question_start:].strip()
            
            response = f"Based on the provided context, here's the answer:\n\n"
            response += f"I found relevant information in the company documents. "
            response += f"The context contains details that help answer your question. "
            response += f"This response is generated using the retrieved documents from the knowledge base."
            
            return response
        
        return "I don't have enough context to answer this question."


class RAGSystem:
    def __init__(self, embedder=None, llm=None, vector_db=None):
        self.embedder = embedder or SimpleEmbedder()
        self.llm = llm or MockLLM()
        self.vector_db = vector_db or SimpleVectorDB()
    
    def load_documents(self, documents: List[Dict[str, Any]]):
        doc_objects = []
        for doc in documents:
            content = doc.get('content', '')
            metadata = doc.get('metadata', {})
            embedding = self.embedder.embed_text(content)
            doc_objects.append(Document(content=content, metadata=metadata, embedding=embedding))
        
        self.vector_db.add_documents(doc_objects)
    
    def load_documents_from_files(self, directory: str):
        documents = []
        for filename in os.listdir(directory):
            filepath = os.path.join(directory, filename)
            if os.path.isfile(filepath):
                with open(filepath, 'r', encoding='utf-8') as f:
                    content = f.read()
                    documents.append({
                        'content': content,
                        'metadata': {'filename': filename, 'source': filepath}
                    })
        
        self.load_documents(documents)
    
    def retrieve(self, query: str, top_k: int = 5) -> List[Document]:
        query_embedding = self.embedder.embed_text(query)
        return self.vector_db.search(query_embedding, top_k=top_k)
    
    def create_prompt(self, query: str, retrieved_docs: List[Document]) -> str:
        prompt = "You are a helpful assistant that answers questions based on company documents.\n\n"
        prompt += "Context Documents:\n"
        prompt += "=" * 80 + "\n\n"
        
        for i, doc in enumerate(retrieved_docs, 1):
            prompt += f"Document {i}:\n"
            prompt += f"Source: {doc.metadata.get('filename', 'Unknown')}\n"
            prompt += f"Content: {doc.content}\n"
            prompt += "-" * 80 + "\n\n"
        
        prompt += "=" * 80 + "\n\n"
        prompt += f"Question: {query}\n\n"
        prompt += "Please provide a comprehensive answer based on the context documents above. "
        prompt += "If the answer is not in the documents, say so.\n\n"
        prompt += "Answer:"
        
        return prompt
    
    def query(self, query: str, top_k: int = 5, return_sources: bool = True) -> Dict[str, Any]:
        retrieved_docs = self.retrieve(query, top_k=top_k)
        
        if not retrieved_docs:
            return {
                'answer': 'No relevant documents found in the knowledge base.',
                'sources': [],
                'retrieved_documents': []
            }
        
        prompt = self.create_prompt(query, retrieved_docs)
        answer = self.llm.generate(prompt)
        
        sources = [doc.metadata for doc in retrieved_docs]
        
        result = {
            'answer': answer,
            'sources': sources,
            'retrieved_documents': [doc.content for doc in retrieved_docs]
        }
        
        if return_sources:
            result['prompt'] = prompt
        
        return result
    
    def save_vector_db(self, filepath: str):
        self.vector_db.save(filepath)
    
    def load_vector_db(self, filepath: str):
        self.vector_db.load(filepath)


